import { apiClient, unwrap } from '@linm-soft/common-components';
import type { BffResponse } from '@linm-soft/common-components';
import type { ContractDto, ContractPagedResult, ContractSearchResult } from './models';

const qsFilter = (filter?: Record<string, string | number | undefined>) => {
  const qs = new URLSearchParams();
  if (!filter) return qs;
  Object.entries(filter).forEach(([k, v]) => {
    if (v !== undefined && v !== '') qs.set(k, String(v));
  });
  return qs;
};

export const salesEndpoint = {
  searchContracts: async (params: {
    search?: string;
    page: number;
    pageSize: number;
    status?: string;
  }): Promise<ContractSearchResult> => {
    const qs = qsFilter({
      search: params.search,
      page: params.page,
      pageSize: params.pageSize,
      status: params.status,
    });
    const res = await apiClient.get<BffResponse<ContractPagedResult>>(`/sales/contracts?${qs}`);
    const data = unwrap(res);
    return {
      items: data.items ?? [],
      page: data.page,
      totalPages: Math.max(1, Math.ceil((data.totalCount ?? 0) / params.pageSize)),
    };
  },

  getContract: async (id: string): Promise<ContractDto> => {
    const res = await apiClient.get<BffResponse<ContractDto>>(`/sales/contracts/${id}`);
    return unwrap(res);
  },

  getContractByCode: async (code: string): Promise<ContractDto | undefined> => {
    const { items } = await salesEndpoint.searchContracts({ search: code, page: 1, pageSize: 20 });
    return items.find(c => c.code === code) ?? items[0];
  },
};
